external_knowledge:
- Active researchers: Those who have accessed any study at least once; 
- Diving into the world of active HCI studies: Engaging with themes that are not only active but also have some HCI-related studies; 
- Represent themselves academically: Their institutional affiliations as listed in the database.

sql:
SELECT t.theme_name, t.theme_category, st.tag_name
FROM themes t
JOIN study_tags st ON t.theme_id = st.study_id;

SELECT users.username, audit_trails.action_details, audit_trails.action_date
FROM users
INNER JOIN audit_trails ON users.user_id = audit_trails.user_id;

SELECT u.username, al.study_id, al.access_date
FROM users u
JOIN user_access_logs al ON u.user_id = al.user_id;

SELECT theme_id, theme_name 
FROM themes 
WHERE theme_id NOT IN (
    SELECT theme_id 
    FROM analytics
);

SELECT DISTINCT u.user_id, u.username
FROM users u
WHERE u.role = 'researcher' AND u.institution = 'specific_institution';
